class PeekingIterator:
    def __init__(self, iterator):
        self.iter = iterator
        self.next_val = self.iter.next() if self.iter.hasNext() else None
    def peek(self):
        return self.next_val
    def next(self):
        res = self.next_val
        self.next_val = self.iter.next() if self.iter.hasNext() else None
        return res
    def hasNext(self):
        return self.next_val is not None

